arguments.command:
cd /tmp/sv-2e1317b3b25e422ab105963fa6f5763d/simple-single-project/MyApp && dotnet list package --format json 2>/dev/null > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)
bp = {p['id']: p['resolvedVersion'] for p in baseline['projects'][0]['frameworks'][0]['topLevelPackages']}
ap = {p['id']: p['resolvedVersion'] for p in after['projects'][0]['frameworks'][0]['topLevelPackages']}
if bp == ap:
    print('All packages resolve to identical versions. Conversion is version-neutral.')
else:
    for pkg in set(list(bp.keys()) + list(ap.keys())):
        bv, av = bp.get(pkg, 'MISSING'), ap.get(pkg, 'MISSING')
        if bv != av: print(f'CHANGED: {pkg} {bv} -> {av}')
"

